// frontend/src/components/jobs/JobDetails.js
import React, { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import api from '../../services/api';
import { useAuth } from '../../contexts/AuthContext';
import './JobDetails.css';
import { useAlert } from '../../contexts/AlertContext';

const JobDetails = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user, isAuthenticated } = useAuth();

    const [job, setJob] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [applying, setApplying] = useState(false);
    const [acceptingId, setAcceptingId] = useState(null);
    const [applicationData, setApplicationData] = useState({
        proposed_rate: '',
        message: '',
        estimated_completion_time: ''
    });

    // Load job details
    useEffect(() => {
        const loadJobDetails = async () => {
            setLoading(true);
            try {
                const response = await api.get(`/jobs/${id}`);
                if (response.data.success) {
                    setJob(response.data.data);
                } else {
                    setError('Job not found');
                }
            } catch (error) {
                console.error('Error loading job:', error);
                setError('Failed to load job details');
            } finally {
                setLoading(false);
            }
        };

        loadJobDetails();
    }, [id]);

    // Handle job application
    const handleApply = async (e) => {
        e.preventDefault();
        if (!isAuthenticated) {
            navigate('/login', { state: { from: `/jobs/${id}` } });
            return;
        }

        if (user?.user_type !== 'worker') {
            alert.error('Only workers can apply for jobs');
            return;
        }

        if (!applicationData.proposed_rate) {
            setError('Please enter your proposed rate');
            return;
        }

        setApplying(true);
        setError('');

        try {
            const response = await api.post(`/jobs/${id}/apply`, {
                proposed_rate: parseInt(applicationData.proposed_rate),
                message: applicationData.message,
                estimated_completion_time: applicationData.estimated_completion_time
            });

            if (response.data.success) {
                alert.success('✅ Application submitted successfully!');
                // Reset form
                setApplicationData({
                    proposed_rate: '',
                    message: '',
                    estimated_completion_time: ''
                });
                // Reload job details to show updated status
                const refreshResponse = await api.get(`/jobs/${id}`);
                if (refreshResponse.data.success) {
                    setJob(refreshResponse.data.data);
                }
            } else {
                setError(response.data.message || 'Failed to apply');
            }
        } catch (error) {
            console.error('Apply error:', error);
            if (error.response?.status === 401) {
                setError('Please login to apply');
                setTimeout(() => navigate('/login'), 2000);
            } else if (error.response?.status === 400) {
                setError(error.response.data.message || 'Invalid application data');
            } else {
                setError(error.response?.data?.message || 'Network error. Please try again.');
            }
        } finally {
            setApplying(false);
        }
    };

    // Handle accept application
    const handleAcceptApplication = async (applicationId) => {
        if (!window.confirm('Are you sure you want to accept this application? This will reject all other applications.')) {
            return;
        }

        setAcceptingId(applicationId);
        setError('');

        try {
            console.log('Accepting application:', applicationId);
            console.log('Job ID:', id);

            const response = await api.post(`/jobs/${id}/accept/${applicationId}`);

            if (response.data.success) {
                alert.success('✅ Application accepted successfully! The worker has been notified.');
                // Reload job details to show updated status
                const refreshResponse = await api.get(`/jobs/${id}`);
                if (refreshResponse.data.success) {
                    setJob(refreshResponse.data.data);
                }
            } else {
                setError(response.data.message || 'Failed to accept application');
            }
        } catch (error) {
            console.error('Accept error:', error);
            console.error('Error response:', error.response?.data);

            if (error.response?.status === 401) {
                setError('Please login to accept applications');
                setTimeout(() => navigate('/login'), 2000);
            } else if (error.response?.status === 403) {
                setError('You are not authorized to accept applications for this job');
            } else if (error.response?.status === 404) {
                setError('Application or job not found');
            } else {
                setError(error.response?.data?.message || 'Failed to accept application. Please try again.');
            }
        } finally {
            setAcceptingId(null);
        }
    };

    // Add this function to handle declining applications
    const handleDeclineApplication = async (applicationId) => {
        if (!window.confirm('Are you sure you want to decline this application?')) {
            return;
        }

        setAcceptingId(applicationId); // Reuse the same loading state
        setError('');

        try {
            const response = await api.post(`/jobs/${id}/decline/${applicationId}`);

            if (response.data.success) {
                alert.info('❌ Application declined');
                // Reload job details to show updated status
                const refreshResponse = await api.get(`/jobs/${id}`);
                if (refreshResponse.data.success) {
                    setJob(refreshResponse.data.data);
                }
            } else {
                alert.error(response.data.message || 'Failed to decline application');
            }
        } catch (error) {
            console.error('Decline error:', error);
            alert.error(error.response?.data?.message || 'Failed to decline application');
        } finally {
            setAcceptingId(null);
        }
    };    

    // Handle input change for application form
    const handleInputChange = (e) => {
        setApplicationData({
            ...applicationData,
            [e.target.name]: e.target.value
        });
    };

    // Format date for display
    const formatDate = (dateString) => {
        if (!dateString) return 'Not specified';
        const date = new Date(dateString);
        return date.toLocaleDateString('en-ZA', {
            day: 'numeric',
            month: 'short',
            year: 'numeric',
            hour: '2-digit',
            minute: '2-digit'
        });
    };

    // Get status badge class
    const getStatusBadgeClass = (status) => {
        switch (status) {
            case 'posted': return 'status-posted';
            case 'assigned': return 'status-assigned';
            case 'in_progress': return 'status-progress';
            case 'completed': return 'status-completed';
            case 'cancelled': return 'status-cancelled';
            default: return '';
        }
    };

    // Get application status badge
    const getApplicationStatusBadge = (status) => {
        switch (status) {
            case 'pending': return 'badge-pending';
            case 'accepted': return 'badge-accepted';
            case 'rejected': return 'badge-rejected';
            default: return '';
        }
    };

    // Get status text
    const getStatusText = (status) => {
        switch (status) {
            case 'posted': return '🟢 Open for Applications';
            case 'assigned': return '🟡 Assigned to Worker';
            case 'in_progress': return '🔵 In Progress';
            case 'completed': return '✅ Completed';
            case 'cancelled': return '❌ Cancelled';
            default: return status;
        }
    };

    if (loading) {
        return (
            <div className="loading-container">
                <div className="loading-spinner">Loading job details...</div>
            </div>
        );
    }

    if (error || !job) {
        return (
            <div className="error-container">
                <h2>❌ Error</h2>
                <p>{error || 'Job not found'}</p>
                <Link to="/jobs" className="btn-primary">Browse Jobs</Link>
            </div>
        );
    }

    const hasApplied = job.applications?.some(app => app.worker_id === user?.id);
    const isOwner = job.client_id === user?.id;
    const isWorker = user?.user_type === 'worker';

    const handleBackClick = () => {
    // Scroll to top before navigating back
    window.scrollTo({
        top: 0,
        left: 0,
        behavior: 'instant'
    });

    // Navigate back after a tiny delay
    setTimeout(() => {
        navigate(-1);
    }, 50);
};

    return (
        <div className="job-details-container">
            <div className="job-details">
                {/* Back button */}
                <div className="back-navigation">
                    <button onClick={handleBackClick} className="back-button">
                        ← Back to Jobs
                    </button>
                </div>

                {/* Header */}
                <div className="job-header">
                    <h1>{job.title}</h1>
                    <div className="job-meta">
                        <span className="meta-item">
                            <span className="meta-icon">📋</span>
                            {job.job_code}
                        </span>
                        <span className="meta-item">
                            <span className="meta-icon">📍</span>
                            {job.township}
                        </span>
                        <span className="meta-item">
                            <span className="meta-icon">📅</span>
                            Posted {formatDate(job.created_at)}
                        </span>
                        <span className={`job-status ${getStatusBadgeClass(job.status)}`}>
                            {getStatusText(job.status)}
                        </span>
                    </div>
                </div>

                {/* Budget Card */}
                <div className="budget-card">
                    <div className="budget-info">
                        <h3>Budget Range</h3>
                        <div className="budget-amount">
                            R {job.budget_min?.toLocaleString()} - R {job.budget_max?.toLocaleString()}
                        </div>
                    </div>
                    {job.estimated_hours && (
                        <div className="budget-note">
                            Estimated {job.estimated_hours} hours
                        </div>
                    )}
                </div>

                {/* Description */}
                <div className="job-description">
                    <h2>📝 Description</h2>
                    <p>{job.description || 'No description provided'}</p>
                </div>

                {/* Details Grid */}
                <div className="details-grid">
                    {job.category && (
                        <div className="detail-card">
                            <h3>Category</h3>
                            <div className="detail-content">{job.category}</div>
                        </div>
                    )}
                    {job.urgency && (
                        <div className="detail-card">
                            <h3>Urgency</h3>
                            <div className="detail-content">
                                {job.urgency === 'urgent' && '🚨 Urgent'}
                                {job.urgency === 'high' && '⚡ High'}
                                {job.urgency === 'medium' && '📋 Medium'}
                                {job.urgency === 'low' && '🟢 Low'}
                            </div>
                        </div>
                    )}
                    {job.preferred_date && (
                        <div className="detail-card">
                            <h3>Preferred Date</h3>
                            <div className="detail-content">{formatDate(job.preferred_date)}</div>
                        </div>
                    )}
                    {job.preferred_time && (
                        <div className="detail-card">
                            <h3>Preferred Time</h3>
                            <div className="detail-content">{job.preferred_time}</div>
                        </div>
                    )}
                </div>

                {/* Materials */}
                {job.materials_provided && (
                    <div className="materials-section">
                        <h2>📦 Materials Provided</h2>
                        <p className="materials-provided">✓ Yes, materials will be provided</p>
                        {job.materials_description && (
                            <p className="materials-description">{job.materials_description}</p>
                        )}
                    </div>
                )}

                {/* Safety Requirements */}
                {job.safety_requirements && (
                    <div className="materials-section">
                        <h2>🛡️ Safety Requirements</h2>
                        <p>{job.safety_requirements}</p>
                    </div>
                )}

                {/* Client Info */}
                <div className="client-card">
                    <div className="client-info">
                        <h3>Posted by</h3>
                        <h2>{job.client_name}</h2>
                        <p className="client-location">
                            <span className="location-icon">📍</span>
                            {job.client_township || job.township}
                        </p>
                        <div className="client-stats">
                            <span className="client-stat">
                                <span className="stat-icon">⭐</span>
                                {job.client_rating || 'New'}
                            </span>
                            <span className="client-stat">
                                <span className="stat-icon">📋</span>
                                {job.client_total_reviews || 0} reviews
                            </span>
                        </div>
                    </div>
                    {isAuthenticated && !isOwner && job.status === 'posted' && (
                        <button 
                            className="btn-contact"
                            onClick={() => alert.info('Messaging feature coming soon!')}
                        >
                            📱 Message Client
                        </button>
                    )}
                </div>

                {/* Applications Section (for job owner) */}
                {isOwner && (
                    <div className="applications-section">
                        <h2>📋 Applications ({job.applications?.length || 0})</h2>

                        {!job.applications || job.applications.length === 0 ? (
                            <div className="no-applications">
                                <p>No applications yet</p>
                                <p className="no-applications-sub">Check back later for responses</p>
                            </div>
                        ) : (
                            <div className="applications-list">
                                {job.applications.map(app => (
                                    <div key={app.id} className={`application-item ${app.status}`}>
                                        <div className="application-item ${app.status}">
                                            <div className="application-header">
                                                <Link to={`/workers/${app.worker_id}`} className="worker-info-link">
                                                    <span className="worker-avatar">
                                                        {app.worker_name?.charAt(0) || '👤'}
                                                    </span>
                                                    <div className="worker-details">
                                                        <span className="worker-name">{app.worker_name}</span>
                                                        <span className="worker-rating">
                                                            ⭐ {app.worker_rating ? Number(app.worker_rating).toFixed(1) : 'New'}
                                                        </span>
                                                    </div>
                                                </Link>
                                                <span className={`application-badge ${getApplicationStatusBadge(app.status)}`}>
                                                    {app.status === 'pending' && '⏳ Pending'}
                                                    {app.status === 'accepted' && '✅ Accepted'}
                                                    {app.status === 'rejected' && '❌ Rejected'}
                                                </span>
                                            </div>

                                            <div className="application-details">
                                                <div className="detail-row">
                                                    <span className="detail-label">💰 Proposed Rate:</span>
                                                    <span className="detail-value">R {app.proposed_rate?.toLocaleString()}</span>
                                                </div>
                                                {app.message && (
                                                    <div className="detail-row">
                                                        <span className="detail-label">📝 Message:</span>
                                                        <span className="detail-value">{app.message}</span>
                                                    </div>
                                                )}
                                                {app.estimated_completion_time && (
                                                    <div className="detail-row">
                                                        <span className="detail-label">⏱️ Estimated Time:</span>
                                                        <span className="detail-value">{app.estimated_completion_time}</span>
                                                    </div>
                                                )}
                                                <div className="detail-row">
                                                    <span className="detail-label">📅 Applied:</span>
                                                    <span className="detail-value">{formatDate(app.created_at)}</span>
                                                </div>

                                                {/* Worker Skills Preview */}
                                                {app.worker_skill && (
                                                    <div className="worker-skills-preview">
                                                        <span className="skill-tag">{app.worker_skill}</span>
                                                    </div>
                                                )}
                                            </div>

                                            {job.status === 'posted' && app.status === 'pending' && (
                                                <div className="application-actions">
                                                    <Link 
                                                        to={`/workers/${app.worker_id}`}
                                                        state={{ from: 'job', jobId: job.id, jobTitle: job.title }} 
                                                        className="btn-view-worker"
                                                    >
                                                        👤 View Full Profile
                                                    </Link>
                                                    <button 
                                                        className="btn-accept"
                                                        onClick={() => handleAcceptApplication(app.id)}
                                                        disabled={acceptingId === app.id}
                                                    >
                                                        {acceptingId === app.id ? (
                                                            <>
                                                                <span className="spinner-small"></span>
                                                                Processing...
                                                            </>
                                                        ) : (
                                                            '✅ Accept Application'
                                                        )}
                                                    </button>
                                                    <button 
                                                        className="btn-decline"
                                                        onClick={() => handleDeclineApplication(app.id)}
                                                        disabled={acceptingId === app.id}
                                                    >
                                                        ❌ Decline
                                                    </button>
                                                </div>
                                            )}

                                            {app.status === 'accepted' && (
                                                <div className="application-accepted-message">
                                                    <span className="accepted-icon">🎉</span>
                                                    This worker has been hired for the job!
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                )}

                {/* Apply Section (for workers) */}
                {isWorker && !isOwner && job.status === 'posted' && (
                    <div className="apply-section">
                        <h2>✍️ Apply for this Job</h2>

                        {hasApplied ? (
                            <div className="already-applied">
                                <span className="applied-icon">✅</span>
                                <div className="applied-text">
                                    <strong>You have already applied for this job</strong>
                                    <p>Check your dashboard for application status</p>
                                </div>
                                <Link to="/dashboard" className="btn-view-applications">
                                    View Applications →
                                </Link>
                            </div>
                        ) : (
                            <form onSubmit={handleApply} className="apply-form">
                                <div className="form-group">
                                    <label>💰 Your Proposed Rate (R) *</label>
                                    <input
                                        type="number"
                                        name="proposed_rate"
                                        value={applicationData.proposed_rate}
                                        onChange={handleInputChange}
                                        placeholder={`Between R${job.budget_min} - R${job.budget_max}`}
                                        min={job.budget_min}
                                        max={job.budget_max}
                                        required
                                    />
                                    <small>Suggested range: R{job.budget_min} - R{job.budget_max}</small>
                                </div>

                                <div className="form-group">
                                    <label>📝 Message to Client</label>
                                    <textarea
                                        name="message"
                                        value={applicationData.message}
                                        onChange={handleInputChange}
                                        placeholder="Tell the client why you're the best person for this job..."
                                        rows="4"
                                    />
                                </div>

                                <div className="form-group">
                                    <label>⏱️ Estimated Completion Time</label>
                                    <input
                                        type="text"
                                        name="estimated_completion_time"
                                        value={applicationData.estimated_completion_time}
                                        onChange={handleInputChange}
                                        placeholder="e.g., 3 hours, tomorrow, by Friday"
                                    />
                                </div>

                                {error && <div className="form-error">{error}</div>}

                                <button 
                                    type="submit" 
                                    className="btn-submit"
                                    disabled={applying}
                                >
                                    {applying ? (
                                        <>
                                            <span className="spinner"></span>
                                            Submitting...
                                        </>
                                    ) : (
                                        '📨 Submit Application'
                                    )}
                                </button>
                            </form>
                        )}
                    </div>
                )}

                {/* Login Prompt for non-authenticated users */}
                {!isAuthenticated && job.status === 'posted' && (
                    <div className="apply-section login-prompt">
                        <p>Want to apply for this job?</p>
                        <Link to="/login" className="btn-primary">
                            Sign in to Apply
                        </Link>
                    </div>
                )}

                {/* Job Status Message for assigned jobs */}
                {job.status === 'assigned' && !isOwner && (
                    <div className="job-status-message">
                        <h3>🔒 This job has been assigned</h3>
                        <p>Applications are closed for this position.</p>
                    </div>
                )}

                {/* Job Status Message for completed jobs */}
                {job.status === 'completed' && (
                    <div className="job-status-message completed">
                        <h3>✅ Job Completed</h3>
                        <p>This job has been marked as complete.</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default JobDetails;
